protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator renamed from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents and raw SQL queries still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id no longer includes the discriminator (was "Product|123", now "123").
        // Preserve the old compound format so existing documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // HasIndex removed ã Cosmos DB throws at startup in EF Core 9.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

